import { Link } from "react-router-dom";
import StatusDetails from "../../../utils/StatusDetails";
import StatusDrop from "../../../utils/StatusDrop";
import { v4 as uuidv4 } from 'uuid';
import { download_file, epochTogmt } from "../../../utils/Common";
import { CButton } from "@coreui/react";

export const tableApplicantsConstant = (fetchApplicantsList) => {
    return [
        {
            id: 1,
            name: "Position",
            selector: (row) => row.position,
            cell: (row) => {
                return (
                    <>
                        <a href={`${process.env.REACT_APP_infratechCareerURL}/${row.jobDescriptionSlug}`} style={{marginRight: "8px"}} target="_blank">
                            <i class="fa-solid fa-external-link" />
                        </a>
                        <Link to={`/career/job-description/edit/${row.jobDescriptionId}`} state={{redirectFromApplicant: true}}>
                            <i class="fa-solid fa-eye" />
                        </Link>
                        <span style={{marginLeft: "8px"}}>{row.position}</span>
                    </>
                );
            },
            sortable: true,
            reorder: true,
            //grow: 2.5,
            width: '300px',
        },
        {
            id: 2,
            name: "Job ID",
            selector: (row) => row.jobId,
            sortable: true,
            reorder: true,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
            //grow: 2.5,
            width: '150px'
        },
        {
            id: 3,
            name: "First Name",
            cell: (row) => {
                return (
                    <Link to={`/career/applicant/${row.id}`}>
                        <span>{row.firstName}</span>
                    </Link>
                );
            },
            sortable: true,
            reorder: true,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
            //grow: 2.5,
            width: '150px'
        },
        {
            id: 4,
            name: "Resume",
            cell: (row) => {
                return (
                    <a className="btn btn-primary" href={"javascript:void(0)"} onClick={(e) => download_file(e, row.resume)}>
                        <i class="fa-solid fa-download" />
                    </a>
                );
            },
            sortable: true,
            reorder: true,
            //grow: 2.5,
            width: '160px',
        },
        {
            id: 5,
            name: "Last Name",
            selector: (row) => row.lastName,
            sortable: true,
            reorder: true,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
            //grow: 2.5,
            width: '150px'
        },
        {
            id: 6,
            name: "Email",
            selector: (row) => row.email,
            sortable: true,
            reorder: true,
            //grow: 3,
            width: '250px'
        },
        {
            id: 7,
            name: "Country Code",
            selector: (row) => "+"+row.countryCode,
            sortable: true,
            reorder: true,
            //grow: 2.5,
            width: '150px',
        },
        {
            id: 8,
            name: "Phone",
            selector: (row) => row.phone,
            sortable: true,
            reorder: true,
            //grow: 2.5,
            width: '150px',
        },
        {
            id: 9,
            name: "Position Type",
            selector: (row) => row?.jobType === "FULL_TIME" ? "Full Time" : "Intern",
            sortable: true,
            reorder: true,
            //grow: 2.5,
            width: '200px',
        },
        {
            id: 10,
            name: "Applied Date",
            selector: (row) => epochTogmt(row.createTime),
            sortable: true,
            reorder: true,
            //grow: 2.5,
            width: '150px',
        },
        {
            id: 11,
            name: "Action",
            cell: (row) => {
                return (
                    <StatusDrop
                        id={row.id}
                        status={row.status}
                        type={'APPLICANT'}
                        action={fetchApplicantsList}
                        key={uuidv4()}
                        publishPermission={""}
                    />
                );
            },
            sortable: true,
            reorder: true,
            //grow: 2.5,
            width: '150px',
        },
        {
            id: 12,
            name: "Status",
            cell: (row) => {
                return (
                    <StatusDetails status={row.status} key={uuidv4()} />
                );
            },
            sortable: true,
            reorder: true,
            //grow: 2.5,
            width: '150px',
        }
    ];
};
